mapper.select:
select word_id, word, replace_text, status, update_time, created_at, updated_at, created_by, updated_by, deleted from sensitive_words
and deleted = false
and word like concat('%', #{keyword}, '%')
and status = #{status}
order by word_id desc limit #{pageSize} offset #{offset}

mapper.insert:
insert into sensitive_words (
  word, replace_text, status, update_time,
  created_at, updated_at, created_by, updated_by, deleted
)
values (
  #{word}, #{replaceText}, #{status}, #{updateTime},
  #{createdAt}, #{updatedAt}, #{createdBy}, #{updatedBy}, #{deleted}
)

mapper.update:
update sensitive_words
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where word_id = #{wordId}
  and deleted = false
